+pub fn discover_optional_beads_dir_with_cli(cli: &CliOverrides) -> Result<Option<PathBuf>> {
+    match discover_beads_dir_with_cli(cli) {
+        Ok(path) => Ok(Some(path)),
+        Err(BeadsError::NotInitialized) if cli.db.is_none() => Ok(None),
